import{_ as n,c as a,o as t,a1 as l}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"Schnellstart: Starten mit Plannotator | plannotator","description":"Erfahren Sie den Schnellstart für Plannotator. Verstehen Sie die Kernfunktionen in 5 Minuten und installieren Sie Claude Code oder OpenCode Plugin.","frontmatter":{"title":"Schnellstart: Starten mit Plannotator | plannotator","sidebarTitle":"5 Minuten Schnellstart","subtitle":"Schnellstart: Starten mit Plannotator","description":"Erfahren Sie den Schnellstart für Plannotator. Verstehen Sie die Kernfunktionen in 5 Minuten und installieren Sie Claude Code oder OpenCode Plugin.","order":1},"headers":[],"relativePath":"de/backnotprop/plannotator/start/index.md","filePath":"de/backnotprop/plannotator/start/index.md"}'),i={name:"de/backnotprop/plannotator/start/index.md"};function r(o,e,s,d,u,h){return t(),a("div",null,[...e[0]||(e[0]=[l('<h1 id="schnellstart" tabindex="-1">Schnellstart <a class="header-anchor" href="#schnellstart" aria-label="Permalink to &quot;Schnellstart&quot;">​</a></h1><p>In diesem Kapitel lernen Sie, Plannotator von Grund auf zu verwenden. Sie erfahren, was Plannotator ist, welche Probleme es lösen kann, und Sie werden die Installation und Konfiguration in Ihrem verwendeten AI Coding Agent (Claude Code oder OpenCode) abschließen.</p><h2 id="inhalt-dieses-kapitels" tabindex="-1">Inhalt dieses Kapitels <a class="header-anchor" href="#inhalt-dieses-kapitels" aria-label="Permalink to &quot;Inhalt dieses Kapitels&quot;">​</a></h2><div class="grid-cards"><h3 id="schnellstart-1" tabindex="-1"><a href="./getting-started/">Schnellstart</a> <a class="header-anchor" href="#schnellstart-1" aria-label="Permalink to &quot;[Schnellstart](./getting-started/)&quot;">​</a></h3><p>Erfahren Sie die Kernfunktionen und Anwendungsfälle von Plannotator und absolvieren Sie Ihr erstes Erlebnis in 5 Minuten. Geeignet für alle neuen Benutzer als erste Einführungsstunde.</p><h3 id="claude-code-plugin-installieren" tabindex="-1"><a href="./installation-claude-code/">Claude Code Plugin installieren</a> <a class="header-anchor" href="#claude-code-plugin-installieren" aria-label="Permalink to &quot;[Claude Code Plugin installieren](./installation-claude-code/)&quot;">​</a></h3><p>Installieren und konfigurieren Sie das Plannotator-Plugin in Claude Code, mit Unterstützung für Plugin-System und manuelle Hook-Methoden, einschließlich lokaler und Remote-Umgebungskonfiguration.</p><h3 id="opencode-plugin-installieren" tabindex="-1"><a href="./installation-opencode/">OpenCode Plugin installieren</a> <a class="header-anchor" href="#opencode-plugin-installieren" aria-label="Permalink to &quot;[OpenCode Plugin installieren](./installation-opencode/)&quot;">​</a></h3><p>Installieren und konfigurieren Sie das Plannotator-Plugin in OpenCode, aktivieren Sie das <code>submit_plan</code> Tool und den <code>/plannotator-review</code> Befehl.</p></div><h2 id="lernpfad" tabindex="-1">Lernpfad <a class="header-anchor" href="#lernpfad" aria-label="Permalink to &quot;Lernpfad&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Empfohlene Reihenfolge</p><ol><li><strong>Zuerst <a href="./getting-started/">Schnellstart</a> lesen</strong>: Erfahren Sie, was Plannotator ist, was es kann, und erstellen Sie ein umfassendes Verständnis</li><li><strong>Dann ein Installations-Tutorial wählen</strong>: Wählen Sie die entsprechende Installationsanleitung basierend auf Ihrem verwendeten AI Coding Agent <ul><li>Claude Code verwenden → <a href="./installation-claude-code/">Claude Code Plugin installieren</a></li><li>OpenCode verwenden → <a href="./installation-opencode/">OpenCode Plugin installieren</a></li></ul></li></ol></div><p>Nach Abschluss der Installation können Sie beginnen, Plannotator für Planprüfung und Codeprüfung zu verwenden.</p><h2 id="nachste-schritte" tabindex="-1">Nächste Schritte <a class="header-anchor" href="#nachste-schritte" aria-label="Permalink to &quot;Nächste Schritte&quot;">​</a></h2><p>Nach Abschluss dieses Kapitels fahren Sie mit <strong><a href="./../platforms/">Plattformfunktionen</a></strong> fort, um die vollständige Verwendung von Planprüfung und Codeprüfung zu beherrschen:</p><ul><li>Grundlagen der Planprüfung: Genehmigen, Ablehnen, Kommentare hinzufügen</li><li>Bildmarkierung: Screenshots an den Plan anhängen und markieren</li><li>Codeprüfung: Git diff visualisieren, zeilenweise Kommentare hinzufügen</li></ul>',10)])])}const f=n(i,[["render",r]]);export{p as __pageData,f as default};
